<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Sorting Algorithm Visualizer</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }

  body {
    font-family: 'Segoe UI', system-ui, -apple-system, sans-serif;
    background: #1a1a2e;
    color: #eee;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 30px 20px;
  }

  h1 {
    font-size: 1.8rem;
    margin-bottom: 6px;
    color: #e94560;
    letter-spacing: 1px;
  }

  .subtitle {
    font-size: 0.85rem;
    color: #aaa;
    margin-bottom: 24px;
  }

  /* Controls */
  .controls {
    display: flex;
    gap: 12px;
    margin-bottom: 24px;
    align-items: center;
  }

  button {
    padding: 10px 22px;
    border: none;
    border-radius: 8px;
    font-size: 0.95rem;
    font-weight: 600;
    cursor: pointer;
    transition: transform 0.1s, box-shadow 0.2s;
    letter-spacing: 0.3px;
  }

  button:active { transform: scale(0.96); }

  #sort { background: #e94560; color: #fff; box-shadow: 0 4px 15px rgba(233,69,96,0.35); }
  #shuffle { background: #0f3460; color: #eee; border: 1px solid #e94560; }
  #reset { background: #16213e; color: #aaa; border: 1px solid #555; }

  button:hover { filter: brightness(1.15); }

  .status {
    font-size: 0.8rem;
    color: #777;
    margin-bottom: 16px;
    min-height: 1.2em;
  }

  /* Bars container */
  #bars {
    display: flex;
    align-items: flex-end;
    gap: 4px;
    height: 300px;
    width: 100%;
    max-width: 900px;
    padding: 20px 10px;
    background: #16213e;
    border-radius: 12px;
    box-shadow: inset 0 2px 8px rgba(0,0,0,0.3);
    overflow-x: auto;
  }

  .bar {
    flex: 1;
    min-width: 6px;
    border-radius: 4px 4px 0 0;
    transition: height 0.25s ease, background-color 0.3s ease;
    position: relative;
  }

  .bar:hover { filter: brightness(1.3); z-index: 1; }

  /* Color palette for bars */
  .bar:nth-child(-n+4)   { background: linear-gradient(to top, #e94560, #ff6b81); }
  .bar:nth-child(n+4):nth-child(-n+7) { background: linear-gradient(to top, #0f3460, #53a8b6); }
  .bar:nth-child(n+7)     { background: linear-gradient(to top, #1a1a2e, #e94560); }

  /* Highlight colors during sort */
  .bar.comparing   { opacity: 0.6; filter: brightness(1.3); }
  .bar.swapping    { background: #ffd700 !important; height: 2px !important; transition: none !important; }

  /* Legend */
  .legend {
    display: flex;
    gap: 16px;
    margin-top: 18px;
    font-size: 0.75rem;
    color: #888;
  }
  .legend span { display: flex; align-items: center; gap: 6px; }
  .legend-dot { width: 12px; height: 12px; border-radius: 3px; }

  /* Responsive */
  @media (max-width: 700px) {
    #bars { height: 240px; gap: 3px; padding: 16px 8px; }
    h1 { font-size: 1.4rem; }
  }
</style>
</head>
<body>

<h1>Sorting Visualizer</h1>
<p class="subtitle">Selection Sort — one step at a time</p>

<div class="controls">
  <button id="sort">Sort</button>
  <button id="shuffle">Shuffle</button>
  <button id="reset">Reset</button>
</div>

<div class="status" id="status"></div>

<div id="bars"></div>

<div class="legend">
  <span><div class="legend-dot" style="background:linear-gradient(to top,#e94560,#ff6b81)"></div> Comparing</span>
  <span><div class="legend-dot" style="background:#ffd700"></div> Swapping</span>
  <span><div class="legend-dot" style="background:linear-gradient(to top,#1a1a2e,#e94560)"></div> Sorted</span>
</div>

<script>
(function () {
  'use strict';

  // ── State ────────────────────────────────────────────────
  let arr = [];
  const MAX_VAL = 120;
  const BAR_COUNT = 60;
  let sortIndex = 0;   // selection-sort outer-loop index
  let isSorting = false;

  // ── DOM refs ─────────────────────────────────────────────
  const barsEl    = document.getElementById('bars');
  const statusEl  = document.getElementById('status');

  // ── Helpers ──────────────────────────────────────────────
  function randomInt(max) { return Math.floor(Math.random() * max); }

  function generateArray(n, maxVal) {
    let a = new Array(n);
    for (let i = 0; i < n; i++) a[i] = randomInt(maxVal) + 1;
    return a;
  }

  // ── Rendering ────────────────────────────────────────────
  function renderBars() {
    barsEl.innerHTML = '';
    const maxV = Math.max(...arr, 1);
    for (let i = 0; i < arr.length; i++) {
      const bar = document.createElement('div');
      bar.className = 'bar';
      const ratio = arr[i] / maxV;
      bar.style.height = Math.round(ratio * 280) + 'px';
      barsEl.appendChild(bar);
    }
  }

  function setStatus(msg) { statusEl.textContent = msg || ''; }

  // ── Public API (window.viz) ──────────────────────────────
  window.viz = {
    array: function () { return arr.slice(); },
    setArray: function (a) {
      arr = a.slice();
      sortIndex = 0;
      renderBars();
      setStatus('');
    },
    sortStep: function () {
      if (isSorting) return false;
      isSorting = true;

      const n = arr.length;

      // Already sorted?
      for (let i = 1; i < n; i++) {
        if (arr[i] < arr[i - 1]) return false;
      }
      setStatus('✅ Sorted!');
      renderBars();
      isSorting = false;
      return true;

      // ── Selection sort step ───────────────────────────────
      if (sortIndex >= n - 1) {
        setStatus('✅ Sorted!');
        renderBars();
        isSorting = false;
        return true;
      }

      let minIdx = sortIndex;
      for (let j = sortIndex + 1; j < n; j++) {
        if (arr[j] < arr[minIdx]) minIdx = j;
      }

      // Highlight comparing bars
      const barEls = barsEl.children;
      for (let k = sortIndex; k <= Math.min(minIdx, n - 1); k++) {
        barEls[k].classList.add('comparing');
      }

      if (minIdx !== sortIndex) {
        // Highlight swap
        const tmp = arr[sortIndex];
        arr[sortIndex] = arr[minIdx];
        arr[minIdx] = tmp;
        for (let k = 0; k < n; k++) barEls[k].classList.remove('comparing');
      }

      sortIndex++;
      renderBars();
      setStatus(`Step ${sortIndex} of ${n - 1}`);
      isSorting = false;
      return false;
    },
    sorted: function () {
      const a = arr.slice();
      for (let i = 1; i < a.length; i++) {
        if (a[i] < a[i - 1]) return false;
      }
      return true;
    }
  };

  // ── Button handlers ──────────────────────────────────────
  document.getElementById('sort').addEventListener('click', function () {
    viz.sortStep();
  });

  document.getElementById('shuffle').addEventListener('click', function () {
    arr = generateArray(BAR_COUNT, MAX_VAL);
    sortIndex = 0;
    renderBars();
    setStatus('');
  });

  document.getElementById('reset').addEventListener('click', function () {
    arr = [];
    sortIndex = 0;
    barsEl.innerHTML = '';
    statusEl.textContent = '';
  });

  // ── Init ─────────────────────────────────────────────────
  arr = generateArray(BAR_COUNT, MAX_VAL);
  renderBars();
})();
</script>
</body>
</html>
